SELECT
    COUNT(*)
FROM patra_ingest.ing_outbox_relay_log
WHERE deleted = 0

    AND channel = #{channel}


    AND relay_status = #{status}


    AND started_at >= #{startTime}


    AND started_at < #{endTime}

SELECT * FROM patra_ingest.ing_outbox_relay_log WHERE relay_status = 'FAILED' AND deleted = 0
AND channel = #{channel}
ORDER BY started_at DESC LIMIT #{limit}


SELECT
    *
FROM patra_ingest.ing_outbox_relay_log
WHERE deleted = 0

    AND channel = #{channel}


    AND started_at >= #{startTime}


    AND started_at < #{endTime}

ORDER BY started_at DESC
LIMIT #{limit}
